namespace Sttop5.Shared.Core
{
    /// <summary>
    /// 游戏模块基类，所有小游戏模块（塔防、消消乐等）继承此类。
    /// 提供模块生命周期管理：加载、激活、停用、卸载。
    /// </summary>
    public abstract class GameModule : MonoBehaviour
    {
        [Header("模块配置")]
        [SerializeField] protected string _moduleId;
        [SerializeField] protected string _displayName;
        [SerializeField] protected string _sceneName;

        /// <summary>模块唯一标识（如 "towerdefense", "match3"）</summary>
        public string ModuleId => _moduleId;

        /// <summary>模块显示名称（如 "塔防", "消消乐"）</summary>
        public string DisplayName => _displayName;

        /// <summary>模块对应场景名</summary>
        public string SceneName => _sceneName;

        /// <summary>模块是否已激活</summary>
        public bool IsActive { get; private set; }

        /// <summary>模块专属事件总线</summary>
        public EventBus EventBus { get; private set; } = new EventBus();

        /// <summary>模块状态变化回调</summary>
        public event Action<GameModule, bool> OnModuleActiveChanged;

        /// <summary>
        /// 模块激活时调用，执行初始化逻辑。
        /// </summary>
        public virtual void Activate()
        {
            IsActive = true;
            OnModuleActiveChanged?.Invoke(this, true);
            Debug.Log($"[GameModule] 模块已激活: {_displayName} ({_moduleId})");
        }

        /// <summary>
        /// 模块停用时调用，执行清理逻辑。
        /// </summary>
        public virtual void Deactivate()
        {
            IsActive = false;
            EventBus.Clear();
            OnModuleActiveChanged?.Invoke(this, false);
            Debug.Log($"[GameModule] 模块已停用: {_displayName} ({_moduleId})");
        }

        /// <summary>
        /// 获取模块存档数据，由 SaveSystem 调用。
        /// </summary>
        public abstract string GetModuleSaveData();

        /// <summary>
        /// 从存档数据恢复模块状态。
        /// </summary>
        public abstract void RestoreModuleSaveData(string jsonData);
    }
}

using System;
using System.Collections.Generic;
using UnityEngine;

namespace Sttop5.Shared.Core
{
    /// <summary>
    /// 模块管理器，负责注册、激活、停用游戏模块。
    /// 管理从家园进入小游戏的完整生命周期。
    /// </summary>
    public class ModuleManager : Singleton<ModuleManager>
    {
        private readonly Dictionary<string, GameModule> _modules = new Dictionary<string, GameModule>();
        private GameModule _activeModule;

        /// <summary>当前激活的模块</summary>
        public GameModule ActiveModule => _activeModule;

        /// <summary>当前激活的模块ID，无模块时为 "home"</summary>
        public string ActiveModuleId => _activeModule != null ? _activeModule.ModuleId : "home";

        /// <summary>模块切换开始回调</summary>
        public event Action<string, string> OnModuleSwitching;

        /// <summary>模块切换完成回调</summary>
        public event Action<string> OnModuleSwitched;

        /// <summary>
        /// 注册一个游戏模块。
        /// </summary>
        public void RegisterModule(GameModule module)
        {
            if (module == null || string.IsNullOrEmpty(module.ModuleId))
            {
                Debug.LogError("[ModuleManager] 无法注册空模块或无ID的模块");
                return;
            }

            if (_modules.ContainsKey(module.ModuleId))
            {
                Debug.LogWarning($"[ModuleManager] 模块已注册，将被替换: {module.ModuleId}");
            }

            _modules[module.ModuleId] = module;
            Debug.Log($"[ModuleManager] 模块已注册: {module.DisplayName} ({module.ModuleId})");
        }

        /// <summary>
        /// 注销一个游戏模块。
        /// </summary>
        public void UnregisterModule(string moduleId)
        {
            if (_modules.ContainsKey(moduleId))
            {
                if (_activeModule != null && _activeModule.ModuleId == moduleId)
                {
                    DeactivateCurrentModule();
                }
                _modules.Remove(moduleId);
                Debug.Log($"[ModuleManager] 模块已注销: {moduleId}");
            }
        }

        /// <summary>
        /// 模块场景名到模块ID的映射，用于场景加载后自动注册。
        /// </summary>
        private readonly Dictionary<string, string> _sceneToModuleId = new Dictionary<string, string>();

        /// <summary>
        /// 激活指定模块，通过场景加载。
        /// 如果模块尚未注册，先加载场景，让场景中的 GameModule 自行注册后再激活。
        /// </summary>
        public void ActivateModule(string moduleId)
        {
            if (!_modules.TryGetValue(moduleId, out GameModule module))
            {
                // 模块尚未注册，可能场景还未加载
                // 尝试通过已知的场景名加载场景，让模块自行注册
                string sceneName = GetKnownSceneName(moduleId);
                if (!string.IsNullOrEmpty(sceneName))
                {
                    Debug.Log($"[ModuleManager] 模块未注册，先加载场景: {sceneName}");
                    ActivateModuleByScene(moduleId, sceneName);
                    return;
                }

                Debug.LogError($"[ModuleManager] 未找到模块: {moduleId}");
                return;
            }

            if (_activeModule != null && _activeModule.ModuleId == moduleId)
            {
                Debug.LogWarning($"[ModuleManager] 模块已激活: {moduleId}");
                return;
            }

            string fromModule = ActiveModuleId;
            OnModuleSwitching?.Invoke(fromModule, moduleId);

            // 停用当前模块
            if (_activeModule != null)
            {
                _activeModule.Deactivate();
            }

            // 加载模块场景
            if (!string.IsNullOrEmpty(module.SceneName))
            {
                SceneLoader.Instance.LoadSceneAdditive(module.SceneName, () =>
                {
                    module.Activate();
                    _activeModule = module;
                    OnModuleSwitched?.Invoke(moduleId);

                    GlobalEventBus.Publish(new ModuleSwitchEvent
                    {
                        FromModule = fromModule,
                        ToModule = moduleId
                    });
                });
            }
            else
            {
                module.Activate();
                _activeModule = module;
                OnModuleSwitched?.Invoke(moduleId);
            }
        }

        /// <summary>
        /// 通过场景加载激活模块（模块尚未注册时使用）。
        /// 加载场景后等待模块自行注册，然后激活。
        /// </summary>
        private void ActivateModuleByScene(string moduleId, string sceneName)
        {
            string fromModule = ActiveModuleId;
            OnModuleSwitching?.Invoke(fromModule, moduleId);

            // 停用当前模块
            if (_activeModule != null)
            {
                _activeModule.Deactivate();
            }

            SceneLoader.Instance.LoadSceneAdditive(sceneName, () =>
            {
                // 场景加载后，模块应该已经自行注册
                if (_modules.TryGetValue(moduleId, out GameModule module))
                {
                    module.Activate();
                    _activeModule = module;
                    OnModuleSwitched?.Invoke(moduleId);

                    GlobalEventBus.Publish(new ModuleSwitchEvent
                    {
                        FromModule = fromModule,
                        ToModule = moduleId
                    });
                }
                else
                {
                    Debug.LogError($"[ModuleManager] 场景 {sceneName} 加载后未找到模块: {moduleId}");
                }
            });
        }

        /// <summary>
        /// 注册模块的场景映射，用于在模块未注册时通过场景名加载。
        /// </summary>
        public void RegisterModuleScene(string moduleId, string sceneName)
        {
            _sceneToModuleId[sceneName] = moduleId;
        }

        /// <summary>
        /// 根据模块ID获取已知的场景名。
        /// </summary>
        private string GetKnownSceneName(string moduleId)
        {
            foreach (var kvp in _sceneToModuleId)
            {
                if (kvp.Value == moduleId)
                    return kvp.Key;
            }

            // 硬编码已知的模块场景映射
            switch (moduleId)
            {
                case "towerdefense": return "TDGameScene";
                case "match3": return "Match3Scene";
                default: return null;
            }
        }

        /// <summary>
        /// 停用当前模块并返回家园。
        /// </summary>
        public void DeactivateCurrentModule()
        {
            if (_activeModule == null)
            {
                Debug.LogWarning("[ModuleManager] 当前无激活模块");
                return;
            }

            string moduleId = _activeModule.ModuleId;
            string sceneName = _activeModule.SceneName;

            _activeModule.Deactivate();

            if (!string.IsNullOrEmpty(sceneName))
            {
                SceneLoader.Instance.UnloadScene(sceneName);
            }

            _activeModule = null;
            Debug.Log($"[ModuleManager] 模块已停用，返回家园: {moduleId}");
        }

        /// <summary>
        /// 获取已注册的模块。
        /// </summary>
        public GameModule GetModule(string moduleId)
        {
            _modules.TryGetValue(moduleId, out GameModule module);
            return module;
        }

        /// <summary>
        /// 获取所有已注册模块。
        /// </summary>
        public IReadOnlyDictionary<string, GameModule> GetAllModules()
        {
            return _modules;
        }

        /// <summary>
        /// 保存所有模块的存档数据。
        /// </summary>
        public Dictionary<string, string> CollectAllModuleSaveData()
        {
            var result = new Dictionary<string, string>();
            foreach (var kvp in _modules)
            {
                try
                {
                    string data = kvp.Value.GetModuleSaveData();
                    if (!string.IsNullOrEmpty(data))
                    {
                        result[kvp.Key] = data;
                    }
                }
                catch (Exception e)
                {
                    Debug.LogError($"[ModuleManager] 获取模块存档失败: {kvp.Key} - {e.Message}");
                }
            }
            return result;
        }
    }
}

using System;
using System.Collections;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.SceneManagement;

namespace Sttop5.Shared.Core
{
    /// <summary>
    /// 场景加载管理器，处理 Additive 场景加载/卸载。
    /// 所有场景切换通过此类进行，支持加载进度回调。
    /// </summary>
    public class SceneLoader : Singleton<SceneLoader>
    {
        private readonly HashSet<string> _loadedScenes = new HashSet<string>();
        private bool _isLoading = false;

        public bool IsLoading => _isLoading;
        public IReadOnlyCollection<string> LoadedScenes => _loadedScenes;

        /// <summary>
        /// 以 Additive 模式加载场景。
        /// </summary>
        public void LoadSceneAdditive(string sceneName, Action onLoaded = null)
        {
            if (_isLoading)
            {
                Debug.LogWarning($"[SceneLoader] 正在加载中，忽略请求: {sceneName}");
                return;
            }

            if (_loadedScenes.Contains(sceneName))
            {
                Debug.LogWarning($"[SceneLoader] 场景已加载: {sceneName}");
                onLoaded?.Invoke();
                return;
            }

            StartCoroutine(LoadSceneAdditiveCoroutine(sceneName, onLoaded));
        }

        /// <summary>
        /// 卸载已加载的 Additive 场景。
        /// </summary>
        public void UnloadScene(string sceneName, Action onUnloaded = null)
        {
            if (!_loadedScenes.Contains(sceneName))
            {
                Debug.LogWarning($"[SceneLoader] 场景未加载，无法卸载: {sceneName}");
                onUnloaded?.Invoke();
                return;
            }

            StartCoroutine(UnloadSceneCoroutine(sceneName, onUnloaded));
        }

        /// <summary>
        /// 卸载所有通过 SceneLoader 加载的场景（保留根场景）。
        /// </summary>
        public void UnloadAllScenes(Action onAllUnloaded = null)
        {
            if (_loadedScenes.Count == 0)
            {
                onAllUnloaded?.Invoke();
                return;
            }

            StartCoroutine(UnloadAllScenesCoroutine(onAllUnloaded));
        }

        /// <summary>
        /// 检查指定场景是否已加载。
        /// </summary>
        public bool IsSceneLoaded(string sceneName)
        {
            return _loadedScenes.Contains(sceneName);
        }

        private IEnumerator LoadSceneAdditiveCoroutine(string sceneName, Action onLoaded)
        {
            _isLoading = true;

            var op = SceneManager.LoadSceneAsync(sceneName, LoadSceneMode.Additive);
            if (op == null)
            {
                Debug.LogError($"[SceneLoader] 无法加载场景: {sceneName}");
                _isLoading = false;
                yield break;
            }

            while (!op.isDone)
            {
                yield return null;
            }

            _loadedScenes.Add(sceneName);

            Scene loadedScene = SceneManager.GetSceneByName(sceneName);
            if (loadedScene.IsValid())
            {
                SceneManager.SetActiveScene(loadedScene);
            }

            _isLoading = false;
            Debug.Log($"[SceneLoader] 场景已加载: {sceneName}");
            onLoaded?.Invoke();
        }

        private IEnumerator UnloadSceneCoroutine(string sceneName, Action onUnloaded)
        {
            _isLoading = true;

            var op = SceneManager.UnloadSceneAsync(sceneName);
            if (op == null)
            {
                Debug.LogError($"[SceneLoader] 无法卸载场景: {sceneName}");
                _isLoading = false;
                yield break;
            }

            while (!op.isDone)
            {
                yield return null;
            }

            _loadedScenes.Remove(sceneName);
            _isLoading = false;
            Debug.Log($"[SceneLoader] 场景已卸载: {sceneName}");
            onUnloaded?.Invoke();
        }

        private IEnumerator UnloadAllScenesCoroutine(Action onAllUnloaded)
        {
            var scenesToUnload = new List<string>(_loadedScenes);
            foreach (var sceneName in scenesToUnload)
            {
                yield return UnloadSceneCoroutine(sceneName, null);
            }
            onAllUnloaded?.Invoke();
        }
    }
}

using UnityEngine;

namespace Sttop5.Shared.Core
{
    /// <summary>
    /// 泛型单例基类，所有需要全局唯一实例的管理器继承此类。
    /// 自动处理 DontDestroyOnLoad 和重复实例销毁。
    /// </summary>
    public abstract class Singleton<T> : MonoBehaviour where T : MonoBehaviour
    {
        private static T _instance;
        private static readonly object _lock = new object();
        private static bool _applicationIsQuitting = false;

        public static T Instance
        {
            get
            {
                if (_applicationIsQuitting)
                {
                    return null;
                }

                lock (_lock)
                {
                    if (_instance == null)
                    {
                        _instance = FindObjectOfType<T>();

                        if (_instance == null)
                        {
                            GameObject go = new GameObject($"[Singleton] {typeof(T).Name}");
                            _instance = go.AddComponent<T>();
                            DontDestroyOnLoad(go);
                        }
                    }
                    return _instance;
                }
            }
        }

        protected virtual void Awake()
        {
            if (_instance == null)
            {
                _instance = this as T;
                transform.SetParent(null);
                DontDestroyOnLoad(gameObject);
            }
            else if (_instance != this)
            {
                Destroy(gameObject);
            }
        }

        protected virtual void OnDestroy()
        {
            if (_instance == this)
            {
                _applicationIsQuitting = true;
            }
        }

        /// <summary>
        /// 重置单例状态，仅用于测试或场景完全重载时。
        /// </summary>
        public static void ResetInstance()
        {
            _applicationIsQuitting = false;
            _instance = null;
        }
    }
}

using System;
using UnityEngine;
using Sttop5.Shared.Core;
using Sttop5.Shared.Save;

namespace Sttop5.Shared.Player
{
    /// <summary>
    /// 统一玩家档案，管理跨所有模块共享的玩家数据。
    /// 包含货币（金币、钻石）、等级、经验值。
    /// </summary>
    public class PlayerProfile : Singleton<PlayerProfile>
    {
        [Header("初始值")]
        [SerializeField] private int _initialGold = 1000;
        [SerializeField] private int _initialDiamond = 100;
        [SerializeField] private int _initialStamina = 60;

        [Header("等级配置")]
        [SerializeField] private int _maxLevel = 99;
        [SerializeField] private int _baseExp = 100;
        [SerializeField] private int _expIncrement = 50;

        private int _gold;
        private int _diamond;
        private int _stamina;
        private int _level = 1;
        private int _currentExp;

        #region 属性

        public int Gold => _gold;
        public int Diamond => _diamond;
        public int Stamina => _stamina;
        public int Level => _level;
        public int CurrentExp => _currentExp;
        public int MaxLevel => _maxLevel;
        public int ExpToNextLevel => GetExpRequiredForLevel(_level);
        public float ExpProgress => _level >= _maxLevel ? 1f : (float)_currentExp / ExpToNextLevel;
        public bool IsMaxLevel => _level >= _maxLevel;

        #endregion

        #region 事件

        public event Action<int> OnGoldChanged;
        public event Action<int> OnDiamondChanged;
        public event Action<int> OnStaminaChanged;
        public event Action<int> OnLevelChanged;
        public event Action<int, int> OnExpChanged;

        #endregion

        protected override void Awake()
        {
            base.Awake();
            _gold = _initialGold;
            _diamond = _initialDiamond;
            _stamina = _initialStamina;
        }

        private void Start()
        {
            LoadFromSave();
        }

        #region 金币

        public bool HasEnoughGold(int amount) => _gold >= amount;

        public void AddGold(int amount, string source = "")
        {
            if (amount <= 0) return;
            _gold += amount;
            OnGoldChanged?.Invoke(_gold);
            GlobalEventBus.Publish(new PlayerCurrencyChangedEvent
            {
                Source = source,
                GoldDelta = amount,
                DiamondDelta = 0
            });
        }

        public bool SpendGold(int amount, string source = "")
        {
            if (!HasEnoughGold(amount)) return false;
            _gold -= amount;
            OnGoldChanged?.Invoke(_gold);
            GlobalEventBus.Publish(new PlayerCurrencyChangedEvent
            {
                Source = source,
                GoldDelta = -amount,
                DiamondDelta = 0
            });
            return true;
        }

        #endregion

        #region 钻石

        public bool HasEnoughDiamond(int amount) => _diamond >= amount;

        public void AddDiamond(int amount, string source = "")
        {
            if (amount <= 0) return;
            _diamond += amount;
            OnDiamondChanged?.Invoke(_diamond);
            GlobalEventBus.Publish(new PlayerCurrencyChangedEvent
            {
                Source = source,
                GoldDelta = 0,
                DiamondDelta = amount
            });
        }

        public bool SpendDiamond(int amount, string source = "")
        {
            if (!HasEnoughDiamond(amount)) return false;
            _diamond -= amount;
            OnDiamondChanged?.Invoke(_diamond);
            GlobalEventBus.Publish(new PlayerCurrencyChangedEvent
            {
                Source = source,
                GoldDelta = 0,
                DiamondDelta = -amount
            });
            return true;
        }

        #endregion

        #region 体力

        public bool HasEnoughStamina(int amount) => _stamina >= amount;

        public void AddStamina(int amount)
        {
            if (amount <= 0) return;
            _stamina += amount;
            OnStaminaChanged?.Invoke(_stamina);
        }

        public bool SpendStamina(int amount)
        {
            if (!HasEnoughStamina(amount)) return false;
            _stamina -= amount;
            OnStaminaChanged?.Invoke(_stamina);
            return true;
        }

        #endregion

        #region 等级与经验

        public int GetExpRequiredForLevel(int level)
        {
            if (level >= _maxLevel) return int.MaxValue;
            return _baseExp + (level - 1) * _expIncrement;
        }

        public void AddExp(int amount)
        {
            if (amount <= 0 || IsMaxLevel) return;

            int oldLevel = _level;
            _currentExp += amount;

            while (_currentExp >= ExpToNextLevel && !IsMaxLevel)
            {
                _currentExp -= ExpToNextLevel;
                _level++;
            }

            if (IsMaxLevel)
                _currentExp = 0;

            OnExpChanged?.Invoke(_currentExp, ExpToNextLevel);
            GlobalEventBus.Publish(new PlayerLevelChangedEvent
            {
                OldLevel = oldLevel,
                NewLevel = _level,
                CurrentExp = _currentExp,
                ExpToNext = ExpToNextLevel
            });

            if (_level != oldLevel)
            {
                OnLevelChanged?.Invoke(_level);
                Debug.Log($"[PlayerProfile] 升级! Lv.{oldLevel} → Lv.{_level}");
            }
        }

        #endregion

        #region 存档

        public void LoadFromSave()
        {
            var saveSystem = SaveSystem.Instance;
            if (saveSystem == null || saveSystem.CurrentSave == null) return;

            var data = saveSystem.CurrentSave.player;
            _gold = data.gold > 0 ? data.gold : _initialGold;
            _diamond = data.diamond > 0 ? data.diamond : _initialDiamond;
            _stamina = data.stamina > 0 ? data.stamina : _initialStamina;
            _level = Mathf.Clamp(data.playerLevel, 1, _maxLevel);
            _currentExp = Mathf.Clamp(data.playerExp, 0, ExpToNextLevel);

            Debug.Log($"[PlayerProfile] 从存档加载: Lv.{_level}, Gold={_gold}, Diamond={_diamond}");
        }

        public void PersistToSave()
        {
            var saveSystem = SaveSystem.Instance;
            if (saveSystem == null || saveSystem.CurrentSave == null) return;

            saveSystem.CurrentSave.player.gold = _gold;
            saveSystem.CurrentSave.player.diamond = _diamond;
            saveSystem.CurrentSave.player.stamina = _stamina;
            saveSystem.CurrentSave.player.playerLevel = _level;
            saveSystem.CurrentSave.player.playerExp = _currentExp;
            saveSystem.SaveGame();
        }

        #endregion

        private void OnApplicationPause(bool pauseStatus)
        {
            if (pauseStatus) PersistToSave();
        }

        private void OnApplicationQuit()
        {
            PersistToSave();
        }

        private void OnDisable()
        {
            PersistToSave();
        }
    }
}

